def checkout_process(cart_items, discount_code, user, payment_info):
    def validate_cart(cart_items):
        if not cart_items:
            return False, "Cart is empty."
        for item in cart_items:
            if item['quantity'] <= 0:
                return False, f"Invalid quantity for item {item['name']}."
        return True, cart_items

    def apply_discount(cart_items, discount_code, user):
        valid_codes = {
            'ADMIN10': {'tier': 'admin', 'discount': 0.10},
            'USER5': {'tier': 'user', 'discount': 0.05}
        }
        if discount_code in valid_codes:
            if valid_codes[discount_code]['tier'] == user['tier']:
                discount = valid_codes[discount_code]['discount']
                total = sum(item['price'] * item['quantity'] for item in cart_items)
                return total * (1 - discount), None
            else:
                return None, "User does not have permission for this discount code."
        return sum(item['price'] * item['quantity'] for item in cart_items), None

    def calculate_tax(total):
        tax_rate = 0.07
        return total * tax_rate

    def process_payment(total, payment_info):
        if payment_info['method'] == 'credit_card' and payment_info['amount'] >= total:
            return True, None
        return False, "Payment failed."

    def create_order_record(cart_items, total, user):
        order = {
            'user_id': user['id'],
            'items': cart_items,
            'total': total,
            'status': 'confirmed'
        }
        return order

    # Step 1: Validate cart items
    valid, message = validate_cart(cart_items)
    if not valid:
        return message

    # Step 2: Apply discount codes
    total, message = apply_discount(cart_items, discount_code, user)
    if message:
        return message

    # Step 3: Calculate tax
    tax = calculate_tax(total)
    total_with_tax = total + tax

    # Step 4: Process payment
    payment_success, message = process_payment(total_with_tax, payment_info)
